	color: #ff00b2;
}

.box span{
	color: #ff7ad7;
}

.box img{
	width: 150px;
	padding: 1rem;
}

.box img.text-img{
	width: 200px;
}

.box input[type="text"],.box input[type="password"]{
	display: block;
	margin: 1.5rem auto;
	padding: 1rem;
	width: 250px;
	background: none;
	outline: none;
	border: 2px solid #ff00b2;
	text-align: center;
	border-radius: 5px;
	transition: 0.25s;
	color: #fff;
}

.box input[type="text"]:focus,.box input[type="password"]:focus{
	width: 280px;
	border-color: #ff7ad7;
}

.box input[type="submit"]{
	display: block;
	margin: 1.5rem auto;
	padding: .6rem .9rem;
	background: none;
	outline: none;
	border: 2px solid #ff00b2;
	text-align: center;
	border-radius: 5px;
	color: #fff;
}

.box input[type="submit"]:hover{
	color: #000;
	font-weight: 600;
	background: #ff7ad7;
	border-color: #ff7ad7;
}

.box p{
	display: block;
	padding: 1rem;
	background: none;
	text-align: center;
	transition: 0.25s;
	overflow-wrap: break-word;
	color: #fff;
}

.box p:focus{
	width: 280px;
	border-color: #ff7ad7;
}

